class ApplicationController < ActionController::Base
  def index
    @before = "<div><p>A goose incident is when a goose displays threatening or aggressive behaviour which is clearly aimed towards a person or group of people.</p>\n\n<p>Read guidance on <a href=\"link%20to%20Whitehall%20page\">what to do during a goose incident</a>.</p>\n\n<div role=\"note\" aria-label=\"Warning\" class=\"application-notice help-notice\">\n<p>Call 999 if you or someone else is in immediate danger.</p>\n</div>\n\n<p>If you’ve been the victim or witness of a goose incident, you can:</p>\n\n<ul>\n  <li><a href=\"link%20to%20start%20page\">report it online</a></li>\n  <li>claim compensation, if you or your property have been damaged by the goose</li>\n  <li>get temporary accommodation, if you cannot stay in your home</li>\n  <li>report someone for causing the incident by provoking the goose or gaggle of geese</li>\n  <li>claim <span class=\"content-block content-block--pension\" data-content-block=\"\" data-document-type=\"pension\" data-content-id=\"156bf8ad-b2d4-44e2-8010-805f74788a01\" data-embed-code=\"{{embed:content_block_pension:pension-amount/rates/pension-rate/amount}}\">£1337.69</span> from the Ministry of Goose Incidents</li>\n</ul>\n\n<div role=\"note\" aria-label=\"Warning\" class=\"application-notice help-notice\">\n<p>You could get a fine of up to £500 if you’re found guilty of causing a goose incident.</p>\n</div>\n\n<h2 id=\"if-a-goose-incident-caused-damage-to-you-or-your-property\">If a goose incident caused damage to you or your property</h2>\n\n<p>You can <a href=\"link%20to%20start%20page\">claim compensation</a> if the incident happened on or after 1 January 2024.</p>\n\n<p>There are 3 levels of goose incidents. The amount you might get depends on the severity of the incident.</p>\n\n<h3 id=\"mild-goose-incident\">Mild goose incident</h3>\n\n<p>This may involve a goose or gaggle of geese:</p>\n\n<ul>\n  <li>hissing at you</li>\n  <li>honking at you</li>\n  <li>following you to see what you’re doing</li>\n  <li>looking through your windows</li>\n</ul>\n\n<p>Mild goose incidents do not usually involve any physical attacks or property damage. </p>\n\n<p>You cannot claim compensation for mild goose incidents.</p>\n\n<h3 id=\"moderate-goose-incident\">Moderate goose incident</h3>\n\n<p>This may involve a goose or gaggle of geese:</p>\n\n<ul>\n  <li>chasing you to try and steal anything you’re carrying</li>\n  <li>causing minor property damage</li>\n  <li>taking things from your garden or home</li>\n</ul>\n\n<p>Moderate goose incidents do not usually involve physical attacks.</p>\n\n<p>You could get up to £250 compensation for moderate goose incidents.</p>\n\n<h3 id=\"severe-goose-incident\">Severe goose incident</h3>\n\n<p>This may involve a goose or gaggle of geese:</p>\n\n<ul>\n  <li>attacking you and causing harm</li>\n  <li>causing serious property damage </li>\n  <li>refusing to leave your property</li>\n</ul>\n\n<p>You could get up to £500 compensation for severe goose incidents.</p>\n\n<h2 id=\"get-temporary-accommodation\">Get temporary accommodation </h2>\n\n<p><a href=\"/find-local-council\">Contact your local council</a> for help getting temporary accommodation if you cannot live in your home because: </p>\n\n<ul>\n  <li>it has been damaged</li>\n  <li>a goose or gaggle of geese have taken over your home</li>\n</ul>\n\n<h2 id=\"if-you-think-someone-is-encouraging-goose-incidents\">If you think someone is encouraging goose incidents</h2>\n\n<p>It’s illegal to deliberately encourage a goose incident by provoking or disturbing a goose or gaggle of geese. </p>\n\n<p>This can include: </p>\n\n<ul>\n  <li>throwing objects at a goose</li>\n  <li>taunting a goose</li>\n  <li>following a goose if they try to move away</li>\n  <li>entering a goose’s territory</li>\n</ul>\n\n<p>You can report someone encouraging goose incidents anonymously to Crimestoppers.</p>\n\n<div class=\"contact\">\n<p>Crimestoppers        <br>\n<a href=\"https://crimestoppers-uk.org/give-information/give-information-online/\">Report crime online</a>    <br>\nTelephone: 0800 555 111    <br>\n24-hour service    <br>\n<a href=\"/call-charges\">Find out about call charges</a>    </p>\n</div>\n\n<h2 id=\"get-advice\">Get advice</h2>\n\n<p>Contact the Ministry of Feathered Affairs if you have questions about a goose incident.</p>\n\n<div class=\"contact\">\n<p>Ministry of Feathered Affairs  <br>\n<a href=\"mailto:goose@mofa.gov.uk\">goose@mofa.gov.uk</a>  <br>\nTelephone: 0800-GOOSE        \nTextphone: 0800-TEXT-GOOSE      <br>\nTuesday to Thursday, 1am to 12pm  <br>\n<a href=\"/call-charges\">Find out about call charges</a>  </p>\n</div>\n\n<div class=\"address\"><div class=\"adr org fn\"><p>\nMinistry of Feathered Affairs  <br>22 Gander Road  <br>Ganderly  <br>GG22 TFL \n</p></div></div>\n\n<p>You will get a reply to your query within 5 days, except on Wednesdays and <a href=\"/bank-holidays\">UK public holidays</a>.</p></div>"
    @after  = "<div><p>Newline</p>\n\n<p>A goose incident is when a goose or geese displays threatening or aggressive behaviour which is clearly aimed towards a person or group of people.</p>\n\n<p>Read guidance on <a href=\"link%20to%20Whitehall%20page\">what to do during a goose incident</a>.</p>\n\n<div role=\"note\" aria-label=\"Warning\" class=\"application-notice help-notice\">\n<p>Call 999 if you or someone else is in immediate danger.</p>\n</div>\n\n<p>If you’ve been the victim or witness of a goose incident, you can:</p>\n\n<ul>\n  <li><a href=\"link%20to%20start%20page\">report it online</a></li>\n  <li>claim compensation, if you or your property have been damaged</li>\n  <li>get temporary accommodation, if you cannot stay in your home because the goose is occupying it</li>\n  <li>report someone for causing the incident by provoking the goose or gaggle of geese</li>\n  <li>claim <span class=\"content-block content-block--pension\" data-content-block=\"\" data-document-type=\"pension\" data-content-id=\"156bf8ad-b2d4-44e2-8010-805f74788a01\" data-embed-code=\"{{embed:content_block_pension:pension-amount/rates/pension-rate/amount}}\">£1337.69</span> from the Ministry of Goose Incidents</li>\n</ul>\n\n<div role=\"note\" aria-label=\"Warning\" class=\"application-notice help-notice\">\n<p>You could get a fine of up to £500 if you’re found guilty of causing a goose incident.</p>\n</div>\n\n<h2 id=\"if-a-goose-incident-caused-damage-to-you-or-your-property\">If a goose incident caused damage to you or your property</h2>\n\n<p>You can <a href=\"link%20to%20start%20page\">claim compensation</a> if the incident happened on or after 1 January 2024.</p>\n\n<p>There are 3 levels of goose incidents. The amount you might get depends on the severity of the incident.</p>\n\n<h3 id=\"mild-goose-incident\">Mild goose incident</h3>\n\n<p>newline</p>\n\n<p>This may involve a goose or gaggle of geese:</p>\n\n<ul>\n  <li>hissing at you</li>\n  <li>honking at you</li>\n  <li>following you to see what you’re doing</li>\n  <li>looking through your windows</li>\n</ul>\n\n<p>Mild goose incidents do not usually involve any physical attacks or property damage. </p>\n\n<p>You cannot claim compensation for mild goose incidents.</p>\n\n<h3 id=\"moderate-goose-incident\">Moderate goose incident</h3>\n\n<p>This may involve a goose or gaggle of geese:</p>\n\n<ul>\n  <li>chasing you to try and steal anything you’re carrying</li>\n  <li>causing minor property damage</li>\n  <li>taking things from your garden or home</li>\n</ul>\n\n<p>Moderate goose incidents do not usually involve physical attacks.</p>\n\n<p>You could get up to £250 compensation for moderate goose incidents.</p>\n\n<h3 id=\"severe-goose-incident\">Severe goose incident</h3>\n\n<p>This may involve a goose or gaggle of geese:</p>\n\n<ul>\n  <li>attacking you and causing harm</li>\n  <li>causing serious property damage </li>\n  <li>refusing to leave your property</li>\n</ul>\n\n<p>You could get up to £500 compensation for severe goose incidents.</p>\n\n<h2 id=\"get-temporary-accommodation\">Get temporary accommodation </h2>\n\n<p><a href=\"/find-local-council\">Contact your local council</a> for help getting temporary accommodation if you cannot live in your home because: </p>\n\n<ul>\n  <li>it has been damaged</li>\n  <li>a goose or gaggle of geese have taken over your home</li>\n</ul>\n\n<h2 id=\"if-you-think-someone-is-encouraging-goose-incidents\">If you think someone is encouraging goose incidents</h2>\n\n<p>It’s illegal to deliberately encourage a goose incident by provoking or disturbing a goose or gaggle of geese. </p>\n\n<p>This can include: </p>\n\n<ul>\n  <li>throwing objects at a goose</li>\n  <li>taunting a goose</li>\n  <li>following a goose if they try to move away</li>\n  <li>entering a goose’s territory</li>\n</ul>\n\n<p>You can report someone encouraging goose incidents anonymously to Crimestoppers.</p>\n\n<div class=\"contact\">\n<p>Crimestoppers        <br>\n<a href=\"https://crimestoppers-uk.org/give-information/give-information-online/\">Report crime online</a>    <br>\nTelephone: 0800 555 111    <br>\n24-hour service    <br>\n<a href=\"/call-charges\">Find out about call charges</a>    </p>\n</div>\n\n<h2 id=\"get-advice\">Get advice</h2>\n\n<p>Contact the Ministry of Feathered Affairs if you have questions about a goose incident.</p>\n\n<div class=\"contact\">\n<p>Ministry of Feathered Affairs  <br>\n<a href=\"mailto:goose@mofa.gov.uk\">goose@mofa.gov.uk</a>  <br>\nTelephone: 0800-GOOSE        \nTextphone: 0800-TEXT-GOOSE      <br>\nTuesday to Thursday, 1am to 12pm  <br>\n<a href=\"/call-charges\">Find out about call charges</a>  </p>\n</div>\n\n<div class=\"address\"><div class=\"adr org fn\"><p>\nMinistry of Feathered Affairs  <br>22 Gander Road  <br>Ganderly  <br>GG22 TFL \n</p></div></div>\n\n<p>You will get a reply to your query within 5 days, except on Wednesdays and <a href=\"/bank-holidays\">UK public holidays</a>.</p></div>"

    # Call your modified gem logic here
    @diff = Nokodiff.diff(@before, @after)
  end
end
